

SELECT setval(pg_get_serial_sequence('unidade_federativa', 'id'), COALESCE((SELECT MAX(id) FROM unidade_federativa), 1), true);
SELECT setval(pg_get_serial_sequence('cidade', 'id'), COALESCE((SELECT MAX(id) FROM cidade), 1), true);

UPDATE paciente p
SET cidade_id = c.id
FROM cidade c
JOIN unidade_federativa uf ON uf.id = c.unidade_federativa_id
WHERE p.cidade_id IS NULL
  AND p.cidade IS NOT NULL
  AND btrim(p.cidade) <> ''
  AND upper(btrim(p.cidade)) = upper(c.nome)
  AND p.uf IS NOT NULL
  AND btrim(p.uf) <> ''
  AND upper(btrim(p.uf)) = upper(uf.sigla);
